// TypeScript implementation for Const Assertions
interface ConstAssertionsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processConstAssertions(item: ConstAssertionsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processConstAssertions({ id: 1, title: 'Const Assertions', status: 'active' }));

